// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup (defense against platform normalization changes)
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKey = apiKeyHeader ? headers[apiKeyHeader] : '';
const expectedKey = $env.RVC_API_KEY;

// Timing-safe comparison - prevents timing attacks on API key
function timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const MAX_LEN = 256;

  // Constant-time length check - fold into result without early exit
  const lenDiff = a.length ^ b.length;  // 0 if lengths equal, non-zero otherwise
  let result = lenDiff;  // Start with length difference already folded in
  // Constant-time comparison: always iterate MAX_LEN, use 0 for out-of-bounds
  for (let i = 0; i < MAX_LEN; i++) {
    const charA = i < a.length ? a.charCodeAt(i) : 0;
    const charB = i < b.length ? b.charCodeAt(i) : 0;
    result |= charA ^ charB;
  }

  return result === 0;
}

// Authentication logic:
// - If server has expectedKey configured: client MUST provide matching key
// - If client provides a key but server has none: reject (unauthorized)
// - If neither configured: allow
if ((expectedKey || providedKey) && !timingSafeEqual(providedKey || '', expectedKey || '')) {
  return [{ json: { valid: false, error: 'Authentication failed' } }];
}

const model = $input.first().json.model || '';
const audioPath = $input.first().json.audio_path || '';

// ENHANCED Path traversal detection
// Blocks: ../, ..\, %2e%2e, %252e%252e (double encoded), null bytes, absolute paths
const pathTraversalPattern = /(\.\.[/\\]|%2e%2e[/\\]|%252e%252e[/\\]|%00|\x00|^\/|^[a-zA-Z]:\\)/i;
let normalizedPath;
try {
  normalizedPath = decodeURIComponent(audioPath).normalize('NFC');
} catch (e) {
  return [{ json: { valid: false, error: 'Invalid audio_path: malformed URL encoding' } }];
}

// Check model name (alphanumeric, dash, underscore only - NO backslashes)
const validModelPattern = /^[a-zA-Z0-9_-]+$/;

// Validate f0_method against allowlist
const validF0Methods = ['harvest', 'pm', 'dio', 'rmvpe', 'crepe', 'crepe-tiny'];
const f0Method = ($input.first().json.f0_method || 'rmvpe').toLowerCase();

// Validate pitch is a number within safe range
const pitch = parseInt($input.first().json.pitch ?? 0, 10);
if (isNaN(pitch) || pitch < -12 || pitch > 12) {
  return [{ json: { valid: false, error: 'Invalid pitch: must be between -12 and +12 semitones' } }];
}

if (pathTraversalPattern.test(audioPath) || pathTraversalPattern.test(normalizedPath)) {
  return [{
    json: {
      valid: false,
      error: 'Path traversal detected: audio_path must not contain directory traversal sequences'
    }
  }];
}

if (model && !validModelPattern.test(model)) {
  return [{
    json: {
      valid: false,
      error: 'Invalid model name: must be alphanumeric, dash, or underscore only'
    }
  }];
}

if (!validF0Methods.includes(f0Method)) {
  return [{ json: { valid: false, error: 'Invalid f0_method: must be one of ' + validF0Methods.join(', ') } }];
}

return [{
  json: {
    valid: true,
    model: model || 'default',
    audio: $input.first().json.audio,
    audio_path: audioPath,
    pitch: pitch,
    f0_method: f0Method
  }
}];

const uploadResponse = $input.first().json || {};
const path = uploadResponse.path || '';

// Must have a path from upload - no fallback to user input
if (!path) {
  return [{ json: { valid: false, error: 'No audio path returned from upload service' } }];
}

// Strict validation: must be /tmp/<alphanumeric>.<ext>
const validPathPattern = /^\/tmp\/[a-zA-Z0-9_-]+\.(wav|mp3|ogg|flac|webm)$/i;

// Path traversal check
const traversalPattern = /(\.\.[/\\]|%2e%2e%2[fF]|%252e%252e%252[fF]|%2[fF]|%252[fF]|%00)/i;

if (traversalPattern.test(path) || !validPathPattern.test(path)) {
  return [{ json: { valid: false, error: 'Invalid upload response path: failed validation' } }];
}

return [{ json: { valid: true, path: path } }];
